diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 2d7524e8018b..6b1c2e1c5a3e 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -1367,6 +1367,51 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
     }
   }

+  // Handle the case where one comparison is on a masked value and implies
+  // the other comparison. For example: (X < C1) & ((X & Mask) == C2)
+  // If the range implied by the masked comparison is a subset of the other
+  // comparison's range, the other comparison is redundant.
+  // Handle the case where one comparison is on a masked value and implies
+  // the other comparison. For example: (X < C1) & ((X & Mask) == C2)
+  // If the range implied by the masked comparison is a subset of the other
+  // comparison's range, the other comparison is redundant.
+  if (V1 != V2 && IsAnd) {
+    Value *X;
+    const APInt *Mask = nullptr;
+    // Check if V2 is V1 & Mask and Pred2 is ICMP_EQ
+    // Pattern: Pred1(V1, C1) & ((V1 & Mask) == C2)
+    if (match(V2, m_c_And(m_Value(X), m_NegatedPower2(Mask))) && X == V1 &&
+        Pred2 == ICmpInst::ICMP_EQ) {
+      // CR1: range where Pred1(V1, C1) is true
+      ConstantRange CRSubset1 = ConstantRange::makeExactICmpRegion(Pred1, *C1);
+      if (Offset1)
+        CRSubset1 = CRSubset1.subtract(*Offset1);
+      // CR2: range where (V1 & Mask) == C2 is true
+      ConstantRange CRSubset2(*C2, *C2 - *Mask);
+      if (Offset2)
+        CRSubset2 = CRSubset2.subtract(*Offset2);
+      // If CR2 implies CR1, we can drop ICmp1
+      if (CRSubset1.contains(CRSubset2))
+        return ICmp2;
+    }
+    // Check if V1 is V2 & Mask and Pred1 is ICMP_EQ
+    // Pattern: ((V2 & Mask) == C1) & Pred2(V2, C2)
+    else if (match(V1, m_c_And(m_Value(X), m_NegatedPower2(Mask))) && X == V2 &&
+             Pred1 == ICmpInst::ICMP_EQ) {
+      // CR2: range where Pred2(V2, C2) is true
+      ConstantRange CRSubset2 = ConstantRange::makeExactICmpRegion(Pred2, *C2);
+      if (Offset2)
+        CRSubset2 = CRSubset2.subtract(*Offset2);
+      // CR1: range where (V2 & Mask) == C1 is true
+      ConstantRange CRSubset1(*C1, *C1 - *Mask);
+      if (Offset1)
+        CRSubset1 = CRSubset1.subtract(*Offset1);
+      // If CR1 implies CR2, we can drop ICmp2
+      if (CRSubset2.contains(CRSubset1))
+        return ICmp1;
+    }
+  }
+
   if (V1 != V2)
     return nullptr;

